/// Verify GitHub artifact attestations for artifact bytes already in memory.
///
/// In-memory counterpart to [`verify_github_attestation`]: the SHA-256 digest is
/// computed over `artifact`, the attestations API is queried for that digest, and
/// the returned bundles are cryptographically verified against the same bytes.
/// Callers use this when the artifact does not exist as a standalone file on
/// disk — e.g. a file contained in a release archive, for projects that attest
/// each file inside the archive rather than the archive blob itself.
pub async fn verify_github_attestation_bytes(
    artifact: &[u8],
    owner: &str,
    repo: &str,
    token: Option<&str>,
    signer_workflow: Option<&str>,
    base_url: Option<&str>,
) -> Result<bool> {
    let mut builder = AttestationClient::builder();
    if let Some(token) = token {
        builder = builder.github_token(token);
    }
    if let Some(base_url) = base_url {
        builder = builder.base_url(base_url);
    }
    let client = builder.build()?;
    let digest = hex::encode(Sha256::digest(artifact));
    let attestations = client
        .fetch_attestations(FetchParams {
            owner: owner.to_string(),
            repo: Some(format!("{owner}/{repo}")),
            digest: format!("sha256:{digest}"),
            limit: 30,
            predicate_type: None,
        })
        .await?;

    if attestations.is_empty() {
        return Err(AttestationError::NoAttestations);
    }

    let mut trust_roots = TrustRoots::default();
    verify_attestation_bundles(&attestations, artifact, signer_workflow, &mut trust_roots).await
}

