pub async fn verify_attestation(
    artifact_path: &Path,
    owner: &str,
    repo: &str,
    expected_workflow: Option<&str>,
    api_url: Option<&str>,
) -> AttestationResult<bool> {
    let token = resolve_token_for_wrapper(api_url);
    let result = match api_url {
        Some(base_url) => {
            mise_sigstore::verify_github_attestation_with_base_url(
                artifact_path,
                owner,
                repo,
                token.as_deref(),
                expected_workflow,
                base_url,
            )
            .await
        }
        None => {
            mise_sigstore::verify_github_attestation(
                artifact_path,
                owner,
                repo,
                token.as_deref(),
                expected_workflow,
            )
            .await
        }
    };
    match result {
        // Some releases attest each file inside an archive rather than the
        // archive blob itself, so the archive's digest has no attestations.
        // Only the `NoAttestations` case falls back — attestations that exist
        // but fail verification are tampering signals and stay hard errors.
        Err(AttestationError::NoAttestations) => {
            verify_archive_member_attestations(
                artifact_path,
                owner,
                repo,
                token.as_deref(),
                expected_workflow,
                api_url,
            )
            .await
        }
        other => other,
    }
}

/// Upper bound on regular files inside an archive that we will verify
/// individually. Each member costs one GitHub attestations API call, and
/// legitimate per-file-attested releases ship a handful of files (binary,
/// license, readme). Beyond the cap we fail closed rather than hammer the API
/// or wave the archive through.
const MAX_ARCHIVE_MEMBERS_TO_VERIFY: usize = 100;

/// Fallback for releases that attest each file inside an archive instead of the
/// archive blob. Verifies every regular file in the archive against the repo's
/// attestations. Fails closed:
///
/// - non-archive artifacts return `NoAttestations` unchanged (no fallback);
/// - an archive that cannot be read, has no regular files, or exceeds
///   [`MAX_ARCHIVE_MEMBERS_TO_VERIFY`] members is a verification error;
/// - any member whose attestations exist but fail verification is an error;
/// - any member without attestations while other members are attested is an
///   error (partial coverage would let a tampered member slip through);
/// - only when *no* member has attestations do we return `NoAttestations`,
///   preserving the caller's SLSA fallthrough for releases that simply don't
///   use GitHub attestations.
async fn verify_archive_member_attestations(
    artifact_path: &Path,
    owner: &str,
    repo: &str,
    token: Option<&str>,
    expected_workflow: Option<&str>,
    api_url: Option<&str>,
) -> AttestationResult<bool> {
    let filename = artifact_path
        .file_name()
        .map(|n| n.to_string_lossy().into_owned())
        .unwrap_or_default();
    let format = TarFormat::from_file_name(&filename);
    if !format.is_archive() {
        return Err(AttestationError::NoAttestations);
    }
    if matches!(format, TarFormat::SevenZip) {
        // 7z member reading isn't wired up; preserve the old behavior
        // (NoAttestations) rather than guessing at verification status.
        debug!("attestation fallback: skipping unsupported 7z archive {filename}");
        return Err(AttestationError::NoAttestations);
    }

    let path = artifact_path.to_path_buf();
    let members = tokio::task::spawn_blocking(move || read_archive_members(&path, format))
        .await
        .map_err(|e| AttestationError::Verification(format!("failed to read archive: {e}")))??;
    if members.is_empty() {
        return Err(AttestationError::Verification(format!(
            "archive {filename} contains no regular files to verify attestations against"
        )));
    }
    debug!(
        "attestation fallback: verifying {} file(s) inside {filename} individually",
        members.len()
    );

    verify_archive_members(&filename, &members, |bytes| {
        mise_sigstore::verify_github_attestation_bytes(
            bytes,
            owner,
            repo,
            token,
            expected_workflow,
            api_url,
        )
    })
    .await
}

/// Verify every archive member against the repo's attestations. See
/// [`verify_archive_member_attestations`] for the fail-closed outcome matrix.
async fn verify_archive_members<F, Fut>(
    filename: &str,
    members: &[(String, Vec<u8>)],
    verify: F,
) -> AttestationResult<bool>
where
    F: Fn(&[u8]) -> Fut,
    Fut: std::future::Future<Output = AttestationResult<bool>>,
{
    let mut verified = 0usize;
    let mut missing: Vec<&str> = Vec::new();
    let mut failures: Vec<String> = Vec::new();
    for (name, bytes) in members {
        match verify(bytes).await {
            Ok(true) => verified += 1,
            Ok(false) => failures.push(format!("{name}: verification returned false")),
            Err(AttestationError::NoAttestations) => missing.push(name),
            Err(e) => failures.push(format!("{name}: {e}")),
        }
    }

    if !failures.is_empty() {
        return Err(AttestationError::Verification(format!(
            "attestation verification failed for file(s) inside {filename}: {}",
            failures.join("; ")
        )));
    }
    if verified == 0 {
        // No member is attested at all — the release doesn't use per-file
        // attestations, so preserve the caller's SLSA fallthrough.
        return Err(AttestationError::NoAttestations);
    }
    if !missing.is_empty() {
        return Err(AttestationError::Verification(format!(
            "release attests files inside {filename} but {} of {} files have no attestation: {}",
            missing.len(),
            members.len(),
            missing.join(", ")
        )));
    }
    Ok(true)
}

/// Read every regular file contained in an archive as `(name, bytes)` pairs.
/// Directories, symlinks, hardlinks, and device nodes carry no content to
/// attest and are skipped. Members are never written to disk, so malicious
/// member paths (e.g. `../`) cannot escape anywhere.
fn read_archive_members(
    archive: &Path,
    format: TarFormat,
) -> AttestationResult<Vec<(String, Vec<u8>)>> {
    let members = match format {
        TarFormat::Zip => read_zip_members(archive)?,
        _ => read_tar_members(archive, format)?,
    };
    if members.len() > MAX_ARCHIVE_MEMBERS_TO_VERIFY {
        return Err(AttestationError::Verification(format!(
