// ------------------------------------------------------------------
// Archive-member attestation fallback tests
// ------------------------------------------------------------------

/// Build an uncompressed tar archive in memory. `dirs` become directory
/// entries, `links` become (`name`, `target`) symlinks — neither should
/// ever show up as a member to verify.
fn build_tar(files: &[(&str, &[u8])], dirs: &[&str], links: &[(&str, &str)]) -> Vec<u8> {
    let mut builder = tar::Builder::new(Vec::new());
    for dir in dirs {
        let mut header = tar::Header::new_gnu();
        header.set_entry_type(tar::EntryType::Directory);
        header.set_mode(0o755);
        header.set_size(0);
        header.set_cksum();
        builder
            .append_data(&mut header, dir, std::io::empty())
            .unwrap();
    }
    for (name, target) in links {
        let mut header = tar::Header::new_gnu();
        header.set_entry_type(tar::EntryType::Symlink);
        header.set_mode(0o777);
        header.set_size(0);
        header.set_link_name(target).unwrap();
        header.set_cksum();
        builder
            .append_data(&mut header, name, std::io::empty())
            .unwrap();
    }
    for (name, contents) in files {
        let mut header = tar::Header::new_gnu();
        header.set_entry_type(tar::EntryType::Regular);
        header.set_mode(0o644);
        header.set_size(contents.len() as u64);
        header.set_cksum();
        builder.append_data(&mut header, name, *contents).unwrap();
    }
    builder.into_inner().unwrap()
}

fn build_zip(files: &[(&str, &[u8])], dirs: &[&str]) -> Vec<u8> {
    use std::io::Write;
    let mut writer = zip::ZipWriter::new(std::io::Cursor::new(Vec::new()));
    let options = zip::write::SimpleFileOptions::default();
    for dir in dirs {
        writer.add_directory(*dir, options).unwrap();
    }
    for (name, contents) in files {
        writer.start_file(*name, options).unwrap();
        writer.write_all(contents).unwrap();
    }
    writer.finish().unwrap().into_inner()
}

fn gzip(bytes: Vec<u8>) -> Vec<u8> {
    use std::io::Write;
    let mut enc =
        flate2::write::GzEncoder::new(Vec::new(), flate2::Compression::default());
    enc.write_all(&bytes).unwrap();
    enc.finish().unwrap()
}

fn xz(bytes: Vec<u8>) -> Vec<u8> {
    use std::io::Write;
    let mut enc = xz2::write::XzEncoder::new(Vec::new(), 6);
    enc.write_all(&bytes).unwrap();
    enc.finish().unwrap()
}

fn bzip2(bytes: Vec<u8>) -> Vec<u8> {
    use std::io::Write;
    let mut enc =
        bzip2::write::BzEncoder::new(Vec::new(), bzip2::Compression::default());
    enc.write_all(&bytes).unwrap();
    enc.finish().unwrap()
}

fn zstd(bytes: Vec<u8>) -> Vec<u8> {
    zstd::stream::encode_all(std::io::Cursor::new(bytes), 0).unwrap()
}

/// Write `bytes` to `filename` inside a fresh temp dir, returning the dir
/// (kept alive by the caller) and the full archive path.
fn temp_archive(filename: &str, bytes: &[u8]) -> (tempfile::TempDir, std::path::PathBuf) {
    let dir = tempfile::tempdir().unwrap();
    let path = dir.path().join(filename);
    std::fs::write(&path, bytes).unwrap();
    (dir, path)
}

fn read_members(path: &Path, format: TarFormat) -> Vec<(String, Vec<u8>)> {
    read_archive_members(path, format).unwrap()
}

fn assert_members(members: &[(String, Vec<u8>)], expected: &[(&str, &[u8])]) {
    let actual: Vec<(&str, &[u8])> = members
        .iter()
        .map(|(name, bytes)| (name.as_str(), bytes.as_slice()))
        .collect();
    assert_eq!(actual, expected);
}

#[test]
fn test_read_members_plain_tar_skips_dirs_and_symlinks() {
    let tar = build_tar(
        &[("tool", b"binary"), ("share/doc/README.md", b"readme")],
        &["share", "share/doc"],
        &[("tool-link", "tool")],
    );
    let (_dir, path) = temp_archive("tool.tar", &tar);
    let members = read_members(&path, TarFormat::Tar);
    assert_members(
        &members,
        &[("tool", b"binary"), ("share/doc/README.md", b"readme")],
    );
}

#[test]
fn test_read_members_tar_gz() {
    let (_dir, path) = temp_archive(
        "tool.tar.gz",
        &gzip(build_tar(&[("bin/tool", b"gz-contents")], &["bin"], &[])),
    );
    let members = read_members(&path, TarFormat::TarGz);
    assert_members(&members, &[("bin/tool", b"gz-contents")]);
}

#[test]
fn test_read_members_tar_xz() {
    let (_dir, path) = temp_archive(
        "tool.tar.xz",
