#[test]
fn test_read_members_zip_skips_directories() {
    let zip = build_zip(
        &[("tool.exe", b"zip-binary"), ("docs/readme.txt", b"zip-readme")],
        &["docs/"],
    );
    let (_dir, path) = temp_archive("tool.zip", &zip);
    let members = read_members(&path, TarFormat::Zip);
