#[test]
fn test_read_members_rejects_corrupt_archive() {
    let (_dir, path) = temp_archive("tool.tar.gz", b"this is not a gzip stream");
    let err = read_archive_members(&path, TarFormat::TarGz).unwrap_err();
    assert!(
