        "corrupt archives must fail closed, got {err}"
    );
}

#[test]
fn test_read_members_enforces_member_cap() {
    let files: Vec<(String, Vec<u8>)> = (0..=MAX_ARCHIVE_MEMBERS_TO_VERIFY)
        .map(|i| (format!("file-{i}"), b"x".to_vec()))
        .collect();
    let specs: Vec<(&str, &[u8])> = files
        .iter()
        .map(|(name, bytes)| (name.as_str(), bytes.as_slice()))
        .collect();
    let (_dir, path) = temp_archive("tool.tar", &build_tar(&specs, &[], &[]));
    let err = read_archive_members(&path, TarFormat::Tar).unwrap_err();
    let msg = err.to_string();
    assert!(
        msg.contains("exceeding the limit"),
        "cap violation should fail closed, got {msg}"
    );
}

/// Canned per-member verifier driven by member contents, so each test can
/// script the exact outcome matrix without touching the network.
fn members(specs: &[(&str, &[u8])]) -> Vec<(String, Vec<u8>)> {
    specs
        .iter()
        .map(|(name, bytes)| (name.to_string(), bytes.to_vec()))
        .collect()
}

async fn verify_by_contents(bytes: &[u8]) -> AttestationResult<bool> {
    match bytes {
        b"good" => Ok(true),
        b"missing" => Err(AttestationError::NoAttestations),
        b"false" => Ok(false),
        _ => Err(AttestationError::Verification("bad signature".to_string())),
    }
}

#[tokio::test]
async fn test_verify_members_all_verified_succeeds() {
    let members = members(&[("tool", b"good"), ("LICENSE", b"good"), ("README.md", b"good")]);
