+    /// Write `bytes` to `filename` inside a fresh temp dir, returning the dir
+    /// (kept alive by the caller) and the full archive path.
+    fn temp_archive(filename: &str, bytes: &[u8]) -> (tempfile::TempDir, std::path::PathBuf) {
+        let dir = tempfile::tempdir().unwrap();
+        let path = dir.path().join(filename);
+        std::fs::write(&path, bytes).unwrap();
+        (dir, path)
+    }
